import React from "react";
import { graphql } from "gatsby";
import { initializeApp } from "firebase/app";
import { getFirestore } from "firebase/firestore/lite";
// import Layout from "@components/layout";
// import BreadCrumb from "@components/common/breadcrumb";
// import MoveForward from "@components/common/move-forward";
import Seo from "@components/seo";
import CentralizedCryptoScreen from "@screens/centralized-crypto";
import { useLocation } from "@reach/router";
import BreadCrumbV2 from "@components/common/breadcrumb-v2";
import Layout_v2 from "@components/layout_v2";

const CentralizedCryptoPage = (props) => {
  const app = initializeApp(props?.data?.site?.siteMetadata?.firestore);
  const db = getFirestore(app);
  const breadcrumbLinks = [
    { text: "Home", link: "/" },
    { text: "Centralized Crypto Exchange Development Company", link: null },
  ];
  const { data } = props;
  const fileUrl =
    data?.centralizedCryptoExchangeImg?.childImageSharp?.gatsbyImageData?.images
      ?.fallback?.src;
  const location = useLocation();
  const validData = data?.allMetaJson?.nodes[0];
  const schemaMarkup = {
    "@context": "https://schema.org",
    "@graph": [
      {
        "@type": "Product",
        name: "Centralized Crypto Exchange Development",
        description:
          "Justtry Technologies is a trusted centralized crypto exchange development company, helping businesses build reliable trading platforms with powerful features, smooth asset handling, and a user-first design that makes every transaction seamless.",
        url: "https://justtrytech.com/centralized-crypto-exchange-development/",
        brand: {
          "@type": "Brand",
          name: "Justtry Technologies",
          logo: "https://justtrytech.com/static/fbe63889a8572c2c3731d1c60a631549/948fb/centralized-crypto-exchange.png",
        },
        aggregateRating: {
          "@type": "AggregateRating",
          ratingValue: 4.6,
          reviewCount: 480,
        },
      },

      {
        "@type": "Organization",
        name: "Justtry Technologies",
        url: "https://justtrytech.com",
        logo: "https://justtrytech.com/static/company_logo-a8a6f67b23da723440dd6bdb258ac7e8.svg",
        description:
          "Centralized crypto exchange development by Justtry Technologies helps businesses build high-performance trading platforms with advanced features, liquidity options, and an intuitive user experience.",
        sameAs: [
          "https://www.linkedin.com/company/justtry-technologies",
          "https://twitter.com/justtrytech",
        ],
        email: "sales@justtrytech.com",
        telephone: "+91 9500139200",
        address: {
          "@type": "PostalAddress",
          streetAddress:
            "179/3, Kamarajar salai, (Near Tamilnadu Chamber of Commerce)",
          addressLocality: "Madurai",
          addressRegion: "Tamilnadu",
          postalCode: "625009",
          addressCountry: "IN",
        },
      },

      {
        "@type": "FAQPage",
        mainEntity: [
          {
            "@type": "Question",
            name: "How to start a CEX business?",
            acceptedAnswer: {
              "@type": "Answer",
              text: "Start a CEX business by defining your market, ensuring regulatory compliance, choosing the right technology, integrating liquidity, enabling strong security, and creating a user-friendly trading experience.",
            },
          },
          {
            "@type": "Question",
            name: "How do centralized exchanges generate revenue?",
            acceptedAnswer: {
              "@type": "Answer",
              text: "Centralized exchanges earn revenue through trading fees, listing fees, withdrawal charges, margin trading interest, and premium services offered to active traders.",
            },
          },
          {
            "@type": "Question",
            name: "What is centralized crypto exchange development?",
            acceptedAnswer: {
              "@type": "Answer",
              text: "Centralized crypto exchange development is the process of creating a digital trading platform where users can buy, sell, and manage cryptocurrencies through an organized system.",
            },
          },
        ],
      },
    ],
  };

  return (
    <Layout_v2 db={db}>
      <Seo
        title={validData?.title}
        metaTitle={validData?.metaTitle}
        metaKeyword={validData?.metaKeyword}
        description={validData?.description}
        image={fileUrl}
        siteFirestore={data?.site?.siteMetadata?.firestore}
        slug={location.pathname.split("/")?.[1]}
        schemaMarkup={schemaMarkup}
      ></Seo>
      <BreadCrumbV2 items={breadcrumbLinks} />
      <main>
        <CentralizedCryptoScreen db={db} />
      </main>
      {/* <MoveForward db={db} /> */}
    </Layout_v2>
  );
};

export default CentralizedCryptoPage;

export const queryData = graphql`
  query MyQuery {
    centralizedCryptoExchangeImg: file(
      relativePath: { eq: "centralized-crypto-exchange.png" }
    ) {
      childImageSharp {
        gatsbyImageData
      }
    }
    site {
      siteMetadata {
        firestore {
          apiKey
          appId
          authDomain
          messagingSenderId
          projectId
          storageBucket
        }
      }
    }
    allMetaJson(
      filter: { slug: { eq: "centralized-crypto-exchange-development" } }
    ) {
      nodes {
        metaTitle
        metaKeyword
        title
        slug
        description
      }
    }
  }
`;
